// frontend/src/pages/HomePage.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

const HomePage = () => {
    const [jobs, setJobs] = useState([]);
    const [stats, setStats] = useState({
        workers: 0,
        clients: 0,
        total_jobs: 0,
        active_jobs: 0,
        completed_jobs: 0,
        total_hires: 0,
        total_revenue: 0
    });
    const [loading, setLoading] = useState({
        jobs: false,
        stats: false
    });

    // Define categories array
    const categories = [
        { name: 'Cleaning', icon: '🧹', jobs: '120+', color: '#E3F2FD' },
        { name: 'Gardening', icon: '🌿', jobs: '85+', color: '#E8F5E9' },
        { name: 'Moving', icon: '📦', jobs: '64+', color: '#FFF3E0' },
        { name: 'Handyman', icon: '🔧', jobs: '156+', color: '#E1F5FE' },
        { name: 'Delivery', icon: '🚚', jobs: '203+', color: '#F3E5F5' },
        { name: 'Painting', icon: '🎨', jobs: '47+', color: '#FFEBEE' }
    ];

    useEffect(() => {
        loadJobs();
        loadStats();
    }, []);

    const loadJobs = async () => {
        setLoading(prev => ({ ...prev, jobs: true }));
        try {
            const response = await api.get('/jobs?status=posted');
            if (response.data.success) {
                setJobs(response.data.data.slice(0, 6));
            }
        } catch (error) {
            console.error('Error loading jobs:', error);
        } finally {
            setLoading(prev => ({ ...prev, jobs: false }));
        }
    };

    const loadStats = async () => {
        setLoading(prev => ({ ...prev, stats: true }));
        try {
            const response = await api.get('/stats');
            if (response.data.success) {
                setStats(response.data.data);
            }
        } catch (error) {
            console.error('Error loading stats:', error);
        } finally {
            setLoading(prev => ({ ...prev, stats: false }));
        }
    };

    // Format numbers with commas
    const formatNumber = (num) => {
        return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    };

    // Define truncateText function
    const truncateText = (text, maxLength = 100) => {
        if (!text) return '';
        return text.length > maxLength ? text.substring(0, maxLength) + '...' : text;
    };

    return (
        <div className="homepage">
            {/* Hero Section */}
            <section className="hero-section">
                <div className="hero-container">
                    <div className="hero-content">
                        <h1 className="hero-title">
                            Connect with local hustlers for any piece job.
                        </h1>
                        <p className="hero-subtitle">
                            Fast, reliable, township service at your fingertips. 
                            <span className="hero-tagline"> Asihlale emakhaya!</span>
                        </p>
                        <div className="hero-buttons">
                            <Link to="/jobs/post" className="btn-primary btn-large">
                                📋 Post a Job
                            </Link>
                            <Link to="/jobs" className="btn-secondary btn-large">
                                🔍 Find Work
                            </Link>
                        </div>
                        <div className="hero-stats">
                            <div className="stat-item">
                                <span className="stat-value">
                                    {loading.stats ? '...' : formatNumber(stats.workers) + '+'}
                                </span>
                                <span className="stat-label">Workers</span>
                            </div>
                            <div className="stat-item">
                                <span className="stat-value">
                                    {loading.stats ? '...' : formatNumber(stats.completed_jobs || stats.total_hires) + '+'}
                                </span>
                                <span className="stat-label">Jobs Done</span>
                            </div>
                        </div>

                        {/* Mini Stats */}
                        <div className="hero-mini-stats">
                            <span>📊 {stats.active_jobs} active jobs</span>
                            <span>💼 {stats.total_hires} hires made</span>
                        </div>
                    </div>
                    <div className="hero-image">
                        <img 
                            src="/images/hero-banner.png" 
                            alt="Township workers" 
                            className="hero-banner"
                            onError={(e) => {
                                e.target.onerror = null;
                                // Use a more reliable fallback
                                e.target.src = 'https://images.unsplash.com/photo-1593113598332-cd288d649433?ixlib=rb-4.0.3&auto=format&fit=crop&w=600&h=400&q=80';
                            }}
                        />
                    </div>
                </div>
            </section>

            {/* Categories Section */}
            <section className="categories-section">
                <div className="container">
                    <div className="section-header">
                        <h2 className="section-title">Popular Categories</h2>
                        <p className="section-subtitle">
                            Browse through our most requested service categories
                        </p>
                    </div>

                    <div className="categories-grid">
                        {categories.map((category, index) => (
                            <Link 
                                to={`/jobs?category=${category.name.toLowerCase()}`} 
                                key={index} 
                                className="category-card"
                                style={{ backgroundColor: category.color }}
                            >
                                <div className="category-icon">{category.icon}</div>
                                <div className="category-info">
                                    <h3 className="category-name">{category.name}</h3>
                                    <p className="category-jobs">{category.jobs} jobs</p>
                                </div>
                            </Link>
                        ))}
                    </div>
                </div>
            </section>

            {/* Why Choose Us Section */}
            <section className="features-section">
                <div className="container">
                    <div className="section-header">
                        <h2 className="section-title">Why Choose Us</h2>
                        <p className="section-subtitle">We make it easy to get things done</p>
                    </div>
                    <div className="features-grid">
                        <div className="feature-card">
                            <div className="feature-icon trusted">🛡️</div>
                            <h3 className="feature-title">Trusted Hustlers</h3>
                            <p className="feature-description">
                                All our hustlers are verified locals from the hood
                            </p>
                        </div>
                        <div className="feature-card">
                            <div className="feature-icon quick">⚡</div>
                            <h3 className="feature-title">Quick Connect</h3>
                            <p className="feature-description">
                                Get connected with workers in minutes, sharp sharp!
                            </p>
                        </div>
                        <div className="feature-card">
                            <div className="feature-icon quality">⭐</div>
                            <h3 className="feature-title">Quality Work</h3>
                            <p className="feature-description">
                                Only the best hustlers, guaranteed satisfaction
                            </p>
                        </div>
                    </div>
                </div>
            </section>

            {/* How It Works Section */}
            <section className="how-it-works">
                <div className="container">
                    <div className="section-header">
                        <h2 className="section-title">How It Works</h2>
                        <p className="section-subtitle">Simple steps to get things done</p>
                    </div>
                    <div className="steps-grid">
                        <div className="step-card">
                            <div className="step-number">1</div>
                            <h3>Post a Job</h3>
                            <p>Tell us what you need done. It's free to post and takes just 2 minutes.</p>
                        </div>
                        <div className="step-card">
                            <div className="step-number">2</div>
                            <h3>Get Offers</h3>
                            <p>Local workers will send you quotes. Check their profiles and ratings.</p>
                        </div>
                        <div className="step-card">
                            <div className="step-number">3</div>
                            <h3>Hire & Pay</h3>
                            <p>Choose your favorite hustler and get the job done. Pay securely with our packages.</p>
                        </div>
                    </div>
                </div>
            </section>

            {/* Recent Jobs Section */}
            <section className="jobs-section">
                <div className="container">
                    <div className="section-header">
                        <h2 className="section-title">Recent Jobs</h2>
                        <p className="section-subtitle">Latest opportunities near you</p>
                    </div>
                    {loading.jobs ? (
                        <div className="loading-spinner">Loading jobs...</div>
                    ) : jobs.length === 0 ? (
                        <div className="no-jobs">
                            <h3>No jobs available</h3>
                            <p>Check back later for opportunities in your area</p>
                            <Link to="/jobs/post" className="btn-primary">
                                Post a Job
                            </Link>
                        </div>
                    ) : (
                        <div className="jobs-grid">
                            {jobs.map(job => (
                                <Link to={`/jobs/${job.id}`} key={job.id} className="job-card">
                                    <div className="job-category">
                                        <span className="category-badge">{job.category || 'General'}</span>
                                    </div>
                                    <h3 className="job-title">{job.title}</h3>
                                    <p className="job-description">
                                        {truncateText(job.description, 80)}
                                    </p>
                                    <div className="job-details">
                                        <div className="job-location">
                                            <span>📍</span>
                                            <span>{job.township}</span>
                                        </div>
                                        <div className="job-budget">
                                            R {job.budget_min} - R {job.budget_max}
                                        </div>
                                    </div>
                                    <div className="job-footer">
                                        <span className="job-time">
                                            {new Date(job.created_at).toLocaleDateString()}
                                        </span>
                                        <span className="btn-apply-small">Apply →</span>
                                    </div>
                                </Link>
                            ))}
                        </div>
                    )}
                    {!loading.jobs && jobs.length > 0 && (
                        <div className="view-more">
                            <Link to="/jobs" className="btn-secondary">
                                View All Jobs →
                            </Link>
                        </div>
                    )}
                </div>
            </section>

            {/* Testimonials Section */}
            <section className="testimonials-section">
                <div className="container">
                    <div className="section-header">
                        <h2 className="section-title">What People Say</h2>
                        <p className="section-subtitle">Real stories from our community</p>
                    </div>
                    <div className="testimonials-grid">
                        <div className="testimonial-card">
                            <div className="testimonial-rating">⭐⭐⭐⭐⭐</div>
                            <p className="testimonial-text">
                                "I found a reliable plumber in minutes. Fixed my leak in no time. Sharp sharp!"
                            </p>
                            <div className="testimonial-author">
                                <strong>Thabo M.</strong>
                                <span>Soweto</span>
                            </div>
                        </div>
                        <div className="testimonial-card">
                            <div className="testimonial-rating">⭐⭐⭐⭐⭐</div>
                            <p className="testimonial-text">
                                "As a hustler, this platform changed my life. Now I get jobs every week."
                            </p>
                            <div className="testimonial-author">
                                <strong>Linda K.</strong>
                                <span>Alexandra</span>
                            </div>
                        </div>
                        <div className="testimonial-card">
                            <div className="testimonial-rating">⭐⭐⭐⭐</div>
                            <p className="testimonial-text">
                                "Easy to use and workers are professional. Will definitely use again."
                            </p>
                            <div className="testimonial-author">
                                <strong>Nomsa D.</strong>
                                <span>Khayelitsha</span>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* USSD Section */}
            <section className="ussd-section">
                <div className="container">
                    <div className="ussd-content">
                        <h2>No smartphone? No problem!</h2>
                        <p>Use USSD on any phone to find work or post jobs</p>
                        <div className="ussd-code">
                            <span className="ussd-label">Dial:</span>
                            <span className="ussd-number">*130*469#</span>
                        </div>
                        <p className="ussd-note">Works on any phone • No data needed • Free to use</p>
                    </div>
                </div>
            </section>

            {/* CTA Section */}
            <section className="cta-section">
                <div className="container">
                    <div className="cta-content">
                        <h2 className="cta-title">Ready to Hustle?</h2>
                        <p className="cta-subtitle">
                            Join thousands of ekasi hustlers making moves every day 🏅
                        </p>
                        <div className="cta-buttons">
                            <Link to="/jobs/post" className="btn-primary btn-large">
                                Post Your First Job
                            </Link>
                            <Link to="/register" className="btn-secondary btn-large">
                                Start Earning Today
                            </Link>
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default HomePage;
